using System.Text.Json;
using System.Text.Json.Nodes;
using NapsternetVClient.Models;
using NapsternetVClient.Utilities;

namespace NapsternetVClient.Converters;

public static class XrayConfigBuilder
{
    private const string TagProxy = "proxy";
    private const string TagDirect = "direct";
    private const string TagBlock = "block";
    private const string TagSocksIn = "socks-in";
    private const string TagHttpIn = "http-in";

    public static string Build(ServerProfile profile, int socksPort = Constants.DefaultSocksPort, int httpPort = Constants.DefaultHttpPort)
    {
        var config = new JsonObject
        {
            ["log"] = new JsonObject { ["loglevel"] = "warning" },
            ["dns"] = BuildDns(profile),
            ["inbounds"] = BuildInbounds(socksPort, httpPort),
            ["outbounds"] = BuildOutbounds(profile),
            ["routing"] = BuildRouting()
        };

        return config.ToJsonString(new JsonSerializerOptions { WriteIndented = true });
    }

    private static JsonObject BuildDns(ServerProfile profile)
    {
        var servers = new JsonArray { "https://1.1.1.1/dns-query", "localhost" };
        if (!string.IsNullOrWhiteSpace(profile.DnsServer))
        {
            servers.Insert(0, profile.DnsServer);
        }

        return new JsonObject
        {
            ["servers"] = servers,
            ["queryStrategy"] = "UseIP"
        };
    }

    private static JsonArray BuildInbounds(int socksPort, int httpPort)
    {
        return new JsonArray
        {
            new JsonObject
            {
                ["tag"] = TagSocksIn,
                ["port"] = socksPort,
                ["listen"] = "127.0.0.1",
                ["protocol"] = "socks",
                ["settings"] = new JsonObject
                {
                    ["auth"] = "noauth",
                    ["udp"] = true,
                    ["ip"] = "127.0.0.1"
                },
                ["sniffing"] = new JsonObject
                {
                    ["enabled"] = true,
                    ["destOverride"] = new JsonArray { "http", "tls", "quic" }
                }
            },
            new JsonObject
            {
                ["tag"] = TagHttpIn,
                ["port"] = httpPort,
                ["listen"] = "127.0.0.1",
                ["protocol"] = "http",
                ["settings"] = new JsonObject(),
                ["sniffing"] = new JsonObject
                {
                    ["enabled"] = true,
                    ["destOverride"] = new JsonArray { "http", "tls", "quic" }
                }
            }
        };
    }

    private static JsonArray BuildOutbounds(ServerProfile profile)
    {
        var outbounds = new JsonArray
        {
            BuildProxyOutbound(profile),
            new JsonObject
            {
                ["tag"] = TagDirect,
                ["protocol"] = "freedom",
                ["settings"] = new JsonObject()
            },
            new JsonObject
            {
                ["tag"] = TagBlock,
                ["protocol"] = "blackhole",
                ["settings"] = new JsonObject
                {
                    ["response"] = new JsonObject { ["type"] = "http" }
                }
            }
        };

        return outbounds;
    }

    private static JsonObject BuildProxyOutbound(ServerProfile profile)
    {
        var outbound = new JsonObject
        {
            ["tag"] = TagProxy,
            ["protocol"] = MapProtocol(profile.Protocol),
            ["settings"] = BuildOutboundSettings(profile)
        };

        var streamSettings = BuildStreamSettings(profile);
        if (streamSettings is not null)
        {
            outbound["streamSettings"] = streamSettings;
        }

        if (profile.MuxEnabled && profile.Protocol is ProxyProtocol.Vmess or ProxyProtocol.Vless)
        {
            outbound["mux"] = new JsonObject
            {
                ["enabled"] = true,
                ["concurrency"] = profile.MuxConcurrency > 0 ? profile.MuxConcurrency : 8
            };
        }

        return outbound;
    }

    private static string MapProtocol(ProxyProtocol protocol) => protocol switch
    {
        ProxyProtocol.Vmess => "vmess",
        ProxyProtocol.Vless => "vless",
        ProxyProtocol.Trojan => "trojan",
        ProxyProtocol.Shadowsocks => "shadowsocks",
        ProxyProtocol.Socks => "socks",
        _ => "freedom"
    };

    private static JsonObject BuildOutboundSettings(ServerProfile profile)
    {
        return profile.Protocol switch
        {
            ProxyProtocol.Vmess => BuildVmessSettings(profile),
            ProxyProtocol.Vless => BuildVlessSettings(profile),
            ProxyProtocol.Trojan => BuildTrojanSettings(profile),
            ProxyProtocol.Shadowsocks => BuildShadowsocksSettings(profile),
            ProxyProtocol.Socks => BuildSocksSettings(profile),
            _ => new JsonObject()
        };
    }

    private static JsonObject BuildVmessSettings(ServerProfile profile)
    {
        return new JsonObject
        {
            ["vnext"] = new JsonArray
            {
                new JsonObject
                {
                    ["address"] = profile.Address,
                    ["port"] = profile.Port,
                    ["users"] = new JsonArray
                    {
                        new JsonObject
                        {
                            ["id"] = profile.UserId,
                            ["alterId"] = profile.AlterId,
                            ["security"] = string.IsNullOrWhiteSpace(profile.Security) ? "auto" : profile.Security
                        }
                    }
                }
            }
        };
    }

    private static JsonObject BuildVlessSettings(ServerProfile profile)
    {
        var user = new JsonObject
        {
            ["id"] = profile.UserId,
            ["encryption"] = "none"
        };

        if (!string.IsNullOrWhiteSpace(profile.Flow))
        {
            user["flow"] = profile.Flow;
        }

        return new JsonObject
        {
            ["vnext"] = new JsonArray
            {
                new JsonObject
                {
                    ["address"] = profile.Address,
                    ["port"] = profile.Port,
                    ["users"] = new JsonArray { user }
                }
            }
        };
    }

    private static JsonObject BuildTrojanSettings(ServerProfile profile)
    {
        return new JsonObject
        {
            ["servers"] = new JsonArray
            {
                new JsonObject
                {
                    ["address"] = profile.Address,
                    ["port"] = profile.Port,
                    ["password"] = profile.Password
                }
            }
        };
    }

    private static JsonObject BuildShadowsocksSettings(ServerProfile profile)
    {
        return new JsonObject
        {
            ["servers"] = new JsonArray
            {
                new JsonObject
                {
                    ["address"] = profile.Address,
                    ["port"] = profile.Port,
                    ["method"] = string.IsNullOrWhiteSpace(profile.Security) ? "aes-256-gcm" : profile.Security,
                    ["password"] = profile.Password
                }
            }
        };
    }

    private static JsonObject BuildSocksSettings(ServerProfile profile)
    {
        var server = new JsonObject
        {
            ["address"] = profile.Address,
            ["port"] = profile.Port
        };

        if (!string.IsNullOrWhiteSpace(profile.UserId) || !string.IsNullOrWhiteSpace(profile.Password))
        {
            server["users"] = new JsonArray
            {
                new JsonObject
                {
                    ["user"] = profile.UserId,
                    ["pass"] = profile.Password
                }
            };
        }

        return new JsonObject
        {
            ["servers"] = new JsonArray { server }
        };
    }

    private static JsonObject? BuildStreamSettings(ServerProfile profile)
    {
        if (profile.Protocol is ProxyProtocol.Socks)
        {
            return null;
        }

        var stream = new JsonObject
        {
            ["network"] = MapNetwork(profile.Network)
        };

        var security = profile.TlsSecurity?.Trim().ToLowerInvariant() ?? string.Empty;
        if (security is "tls" or "xtls")
        {
            stream["security"] = "tls";
            stream["tlsSettings"] = BuildTlsSettings(profile);
        }
        else if (security is "reality")
        {
            stream["security"] = "reality";
            stream["realitySettings"] = BuildRealitySettings(profile);
        }

        var transport = BuildTransportSettings(profile);
        foreach (var (key, value) in transport)
        {
            stream[key] = value?.DeepClone();
        }

        return stream;
    }

    private static string MapNetwork(TransportType network) => network switch
    {
        TransportType.Ws => "ws",
        TransportType.Grpc => "grpc",
        TransportType.H2 => "h2",
        TransportType.Quic => "quic",
        TransportType.Kcp => "kcp",
        _ => "tcp"
    };

    private static JsonObject BuildTlsSettings(ServerProfile profile)
    {
        var tls = new JsonObject
        {
            ["allowInsecure"] = profile.AllowInsecure,
            ["serverName"] = string.IsNullOrWhiteSpace(profile.Sni) ? profile.Address : profile.Sni
        };

        if (!string.IsNullOrWhiteSpace(profile.Alpn))
        {
            tls["alpn"] = new JsonArray(profile.Alpn.Split(',', StringSplitOptions.RemoveEmptyEntries | StringSplitOptions.TrimEntries));
        }

        if (!string.IsNullOrWhiteSpace(profile.Fingerprint))
        {
            tls["fingerprint"] = profile.Fingerprint;
        }

        return tls;
    }

    private static JsonObject BuildRealitySettings(ServerProfile profile)
    {
        return new JsonObject
        {
            ["show"] = false,
            ["serverName"] = string.IsNullOrWhiteSpace(profile.Sni) ? profile.Address : profile.Sni,
            ["publicKey"] = profile.RealityPublicKey,
            ["shortId"] = profile.RealityShortId,
            ["spiderX"] = string.IsNullOrWhiteSpace(profile.RealitySpiderX) ? "/" : profile.RealitySpiderX,
            ["fingerprint"] = string.IsNullOrWhiteSpace(profile.Fingerprint) ? "chrome" : profile.Fingerprint
        };
    }

    private static Dictionary<string, JsonNode?> BuildTransportSettings(ServerProfile profile)
    {
        return profile.Network switch
        {
            TransportType.Ws => new Dictionary<string, JsonNode?>
            {
                ["wsSettings"] = new JsonObject
                {
                    ["path"] = string.IsNullOrWhiteSpace(profile.WsPath) ? "/" : profile.WsPath,
                    ["headers"] = new JsonObject
                    {
                        ["Host"] = string.IsNullOrWhiteSpace(profile.WsHost) ? profile.Address : profile.WsHost
                    }
                }
            },
            TransportType.Grpc => new Dictionary<string, JsonNode?>
            {
                ["grpcSettings"] = new JsonObject
                {
                    ["serviceName"] = profile.GrpcServiceName,
                    ["multiMode"] = string.Equals(profile.GrpcMode, "multi", StringComparison.OrdinalIgnoreCase)
                }
            },
            TransportType.H2 => new Dictionary<string, JsonNode?>
            {
                ["httpSettings"] = new JsonObject
                {
                    ["path"] = string.IsNullOrWhiteSpace(profile.H2Path) ? "/" : profile.H2Path,
                    ["host"] = new JsonArray
                    {
                        string.IsNullOrWhiteSpace(profile.H2Host) ? profile.Address : profile.H2Host
                    }
                }
            },
            TransportType.Tcp when string.Equals(profile.TcpHeaderType, "http", StringComparison.OrdinalIgnoreCase) =>
                new Dictionary<string, JsonNode?>
                {
                    ["tcpSettings"] = new JsonObject
                    {
                        ["header"] = new JsonObject
                        {
                            ["type"] = "http",
                            ["request"] = new JsonObject
                            {
                                ["path"] = new JsonArray
                                {
                                    string.IsNullOrWhiteSpace(profile.TcpPath) ? "/" : profile.TcpPath
                                },
                                ["headers"] = new JsonObject
                                {
                                    ["Host"] = new JsonArray
                                    {
                                        string.IsNullOrWhiteSpace(profile.TcpHost) ? profile.Address : profile.TcpHost
                                    }
                                }
                            }
                        }
                    }
                },
            _ => new Dictionary<string, JsonNode?>()
        };
    }

    private static JsonObject BuildRouting()
    {
        return new JsonObject
        {
            ["domainStrategy"] = "IPIfNonMatch",
            ["rules"] = new JsonArray
            {
                new JsonObject
                {
                    ["type"] = "field",
                    ["inboundTag"] = new JsonArray { TagSocksIn, TagHttpIn },
                    ["port"] = "53",
                    ["network"] = "udp",
                    ["outboundTag"] = TagDirect
                },
                new JsonObject
                {
                    ["type"] = "field",
                    ["ip"] = new JsonArray { "geoip:private" },
                    ["outboundTag"] = TagDirect
                },
                new JsonObject
                {
                    ["type"] = "field",
                    ["domain"] = new JsonArray { "geosite:private" },
                    ["outboundTag"] = TagDirect
                },
                new JsonObject
                {
                    ["type"] = "field",
                    ["domain"] = new JsonArray { "geosite:cn" },
                    ["outboundTag"] = TagDirect
                },
                new JsonObject
                {
                    ["type"] = "field",
                    ["ip"] = new JsonArray { "geoip:cn" },
                    ["outboundTag"] = TagDirect
                },
                new JsonObject
                {
                    ["type"] = "field",
                    ["network"] = "tcp,udp",
                    ["outboundTag"] = TagProxy
                }
            }
        };
    }
}

using System.Diagnostics;
using System.Text;
using Microsoft.Extensions.Logging;
using NapsternetVClient.Utilities;

namespace NapsternetVClient.Core;

public sealed class XrayProcessManager : IDisposable
{
    private readonly ILogger? _logger;
    private Process? _process;
    private bool _disposed;

    public event EventHandler<string>? LogReceived;
    public event EventHandler<int>? ProcessExited;

    public bool IsRunning => _process is { HasExited: false };

    public XrayProcessManager(ILogger? logger = null)
    {
        _logger = logger;
    }

    public async Task StartAsync(string configPath, CancellationToken cancellationToken = default)
    {
        ObjectDisposedException.ThrowIf(_disposed, this);

        if (IsRunning)
        {
            throw new InvalidOperationException("Xray is already running.");
        }

        if (!File.Exists(Constants.XrayExePath))
        {
            throw new FileNotFoundException("xray.exe was not found.", Constants.XrayExePath);
        }

        if (!File.Exists(configPath))
        {
            throw new FileNotFoundException("Xray config file was not found.", configPath);
        }

        var psi = new ProcessStartInfo
        {
            FileName = Constants.XrayExePath,
            Arguments = $"run -c \"{configPath}\"",
            WorkingDirectory = Constants.BinDir,
            UseShellExecute = false,
            RedirectStandardOutput = true,
            RedirectStandardError = true,
            CreateNoWindow = true,
            StandardOutputEncoding = Encoding.UTF8,
            StandardErrorEncoding = Encoding.UTF8
        };

        _process = new Process { StartInfo = psi, EnableRaisingEvents = true };
        _process.OutputDataReceived += OnOutputDataReceived;
        _process.ErrorDataReceived += OnErrorDataReceived;
        _process.Exited += OnExited;

        if (!_process.Start())
        {
            throw new InvalidOperationException("Failed to start xray.exe.");
        }

        _process.BeginOutputReadLine();
        _process.BeginErrorReadLine();

        await WaitForReadyAsync(cancellationToken).ConfigureAwait(false);
        _logger?.LogInformation("xray.exe started (PID {Pid})", _process.Id);
    }

    public Task StopAsync()
    {
        if (_process is null || _process.HasExited)
        {
            return Task.CompletedTask;
        }

        try
        {
            _process.Kill(entireProcessTree: true);
            _logger?.LogInformation("xray.exe stopped.");
        }
        catch (Exception ex)
        {
            _logger?.LogWarning(ex, "Failed to stop xray.exe cleanly.");
        }

        return Task.CompletedTask;
    }

    private async Task WaitForReadyAsync(CancellationToken cancellationToken)
    {
        const int maxAttempts = 20;
        for (var attempt = 0; attempt < maxAttempts; attempt++)
        {
            cancellationToken.ThrowIfCancellationRequested();

            if (_process is null || _process.HasExited)
            {
                throw new InvalidOperationException("xray.exe exited during startup.");
            }

            await Task.Delay(100, cancellationToken).ConfigureAwait(false);
            return;
        }
    }

    private void OnOutputDataReceived(object sender, DataReceivedEventArgs e)
    {
        if (string.IsNullOrWhiteSpace(e.Data))
        {
            return;
        }

        var line = LogRedactor.Redact(e.Data);
        LogReceived?.Invoke(this, line);
        _logger?.LogDebug("[xray] {Line}", line);
    }

    private void OnErrorDataReceived(object sender, DataReceivedEventArgs e)
    {
        if (string.IsNullOrWhiteSpace(e.Data))
        {
            return;
        }

        var line = LogRedactor.Redact(e.Data);
        LogReceived?.Invoke(this, line);
        _logger?.LogWarning("[xray] {Line}", line);
    }

    private void OnExited(object? sender, EventArgs e)
    {
        var exitCode = _process?.ExitCode ?? -1;
        ProcessExited?.Invoke(this, exitCode);
        _logger?.LogInformation("xray.exe exited with code {ExitCode}", exitCode);
    }

    public void Dispose()
    {
        if (_disposed)
        {
            return;
        }

        _disposed = true;

        if (_process is not null)
        {
            _process.OutputDataReceived -= OnOutputDataReceived;
            _process.ErrorDataReceived -= OnErrorDataReceived;
            _process.Exited -= OnExited;

            if (!_process.HasExited)
            {
                try
                {
                    _process.Kill(entireProcessTree: true);
                }
                catch
                {
                    // Best effort cleanup.
                }
            }

            _process.Dispose();
            _process = null;
        }
    }
}

using System.Diagnostics;
