            ["dns"] = new JsonObject
            {
                ["servers"] = new JsonArray
                {
                    new JsonObject
                    {
                        ["tag"] = "remote",
                        ["address"] = "1.1.1.1",
                        ["detour"] = "proxy"
                    },
                    new JsonObject
                    {
                        ["tag"] = "local",
                        ["address"] = "223.5.5.5",
                        ["detour"] = "direct"
                    }
                },
                ["strategy"] = "prefer_ipv4"
            },
            ["inbounds"] = new JsonArray
            {
                new JsonObject
                {
                    ["type"] = "tun",
                    ["tag"] = "tun-in",
                    ["interface_name"] = interfaceName,
                    ["inet4_address"] = "172.19.0.1/30",
                    ["auto_route"] = true,
                    ["strict_route"] = true,
                    ["stack"] = "system",
                    ["sniff"] = true,
                    ["sniff_override_destination"] = true
                }
            },
            ["outbounds"] = new JsonArray
