                    ["version"] = "5",
                    ["udp_over_tcp"] = new JsonObject { ["enabled"] = true }
                },
                new JsonObject { ["type"] = "direct", ["tag"] = "direct" },
                new JsonObject { ["type"] = "block", ["tag"] = "block" }
            },
            ["route"] = new JsonObject
            {
                ["auto_detect_interface"] = true,
                ["final"] = "proxy",
                ["rules"] = new JsonArray
                {
                    new JsonObject
                    {
                        ["ip_is_private"] = true,
