using System.Diagnostics;
using System.IO.Compression;
using System.Net.Http.Headers;
using System.Text.Json;
using Microsoft.Extensions.Logging;
using NapsternetVClient.Utilities;

namespace NapsternetVClient.Core;

public sealed class BinaryManager
{
    private const string GeoIpUrl = "https://github.com/Loyalsoldier/v2ray-rules-dat/releases/latest/download/geoip.dat";
    private const string GeoSiteUrl = "https://github.com/Loyalsoldier/v2ray-rules-dat/releases/latest/download/geosite.dat";

    private static readonly HttpClient Http = new()
    {
        Timeout = TimeSpan.FromMinutes(10)
    };

    static BinaryManager()
    {
        Http.DefaultRequestHeaders.UserAgent.ParseAdd("NapsternetVClient/1.0");
        Http.DefaultRequestHeaders.Accept.Add(new MediaTypeWithQualityHeaderValue("application/vnd.github+json"));
    }

    private readonly ILogger? _logger;

    public BinaryManager(ILogger? logger = null)
    {
        _logger = logger;
    }

    public async Task EnsureAllAsync(IProgress<string>? progress = null, CancellationToken cancellationToken = default)
    {
        Constants.EnsureDirectories();
        progress?.Report("Checking xray-core...");
        await EnsureXrayAsync(progress, cancellationToken).ConfigureAwait(false);

        progress?.Report("Checking sing-box...");
        await EnsureSingBoxAsync(progress, cancellationToken).ConfigureAwait(false);

        progress?.Report("Checking wintun...");
        await EnsureWintunAsync(progress, cancellationToken).ConfigureAwait(false);

        progress?.Report("Checking geo files...");
        await EnsureGeoFilesAsync(progress, cancellationToken).ConfigureAwait(false);

        progress?.Report("Checking npvt-decoder...");
        await EnsureNpvtDecoderAsync(progress, cancellationToken).ConfigureAwait(false);
    }

    public bool AreBinariesPresent() =>
        File.Exists(Constants.XrayExePath) &&
        File.Exists(Constants.SingBoxExePath) &&
        File.Exists(Constants.WintunDllPath) &&
        File.Exists(Constants.NpvtDecoderExePath) &&
        File.Exists(Path.Combine(Constants.BinDir, "geoip.dat")) &&
        File.Exists(Path.Combine(Constants.BinDir, "geosite.dat"));

    public async Task EnsureXrayAsync(IProgress<string>? progress = null, CancellationToken cancellationToken = default)
    {
        if (File.Exists(Constants.XrayExePath))
        {
            return;
        }

        progress?.Report("Downloading xray-core...");
        var assetUrl = await GetReleaseAssetUrlAsync(
            Constants.XrayReleaseApiUrl,
            name => name.Contains("windows-64", StringComparison.OrdinalIgnoreCase) &&
                    name.EndsWith(".zip", StringComparison.OrdinalIgnoreCase),
            cancellationToken).ConfigureAwait(false);

        var zipPath = Path.Combine(Constants.BinDir, "xray.zip");
        await DownloadFileAsync(assetUrl, zipPath, cancellationToken).ConfigureAwait(false);
        await ExtractExeFromZipAsync(zipPath, Constants.XrayExePath, "xray.exe", cancellationToken).ConfigureAwait(false);
        File.Delete(zipPath);
    }

    public async Task EnsureSingBoxAsync(IProgress<string>? progress = null, CancellationToken cancellationToken = default)
    {
        if (File.Exists(Constants.SingBoxExePath))
        {
            return;
        }

        progress?.Report("Downloading sing-box...");
        var assetUrl = await GetReleaseAssetUrlAsync(
            Constants.SingBoxReleaseApiUrl,
