    public async Task EnsureWintunAsync(IProgress<string>? progress = null, CancellationToken cancellationToken = default)
    {
        if (File.Exists(Constants.WintunDllPath))
        {
            return;
        }

        progress?.Report("Downloading wintun...");
        var zipPath = Path.Combine(Constants.BinDir, "wintun.zip");
