        using var archive = ZipFile.OpenRead(zipPath);
        var entry = archive.Entries.FirstOrDefault(e =>
            e.FullName.Contains("amd64", StringComparison.OrdinalIgnoreCase) &&
            e.Name.Equals("wintun.dll", StringComparison.OrdinalIgnoreCase));

        if (entry is null)
        {
            throw new InvalidOperationException("wintun.dll (amd64) not found in wintun archive.");
        }

        entry.ExtractToFile(Constants.WintunDllPath, overwrite: true);
        File.Delete(zipPath);
