        var geoSitePath = Path.Combine(Constants.BinDir, "geosite.dat");

        if (!File.Exists(geoIpPath))
        {
            progress?.Report("Downloading geoip.dat...");
            await DownloadFileAsync(GeoIpUrl, geoIpPath, cancellationToken).ConfigureAwait(false);
        }

        if (!File.Exists(geoSitePath))
        {
            progress?.Report("Downloading geosite.dat...");
            await DownloadFileAsync(GeoSiteUrl, geoSitePath, cancellationToken).ConfigureAwait(false);
        }
    }

    public async Task EnsureNpvtDecoderAsync(IProgress<string>? progress = null, CancellationToken cancellationToken = default)
    {
        if (File.Exists(Constants.NpvtDecoderExePath))
        {
            return;
        }

        progress?.Report("Downloading Pantegnos npvt-decoder...");
        var assetUrl = await GetReleaseAssetUrlAsync(
            Constants.PantegnosReleaseApiUrl,
            name => (name.Contains("windows", StringComparison.OrdinalIgnoreCase) &&
                     name.Contains("amd64", StringComparison.OrdinalIgnoreCase)) &&
                    name.EndsWith(".exe", StringComparison.OrdinalIgnoreCase),
            cancellationToken).ConfigureAwait(false);

        await DownloadFileAsync(assetUrl, Constants.NpvtDecoderExePath, cancellationToken).ConfigureAwait(false);
    }

    private static async Task<string> GetReleaseAssetUrlAsync(
        string apiUrl,
        Func<string, bool> assetMatcher,
        CancellationToken cancellationToken)
    {
        using var response = await Http.GetAsync(apiUrl, cancellationToken).ConfigureAwait(false);
        response.EnsureSuccessStatusCode();

        await using var stream = await response.Content.ReadAsStreamAsync(cancellationToken).ConfigureAwait(false);
        using var document = await JsonDocument.ParseAsync(stream, cancellationToken: cancellationToken).ConfigureAwait(false);

        if (!document.RootElement.TryGetProperty("assets", out var assets))
        {
            throw new InvalidOperationException($"No assets found in release: {apiUrl}");
        }

        foreach (var asset in assets.EnumerateArray())
        {
            var name = asset.GetProperty("name").GetString() ?? string.Empty;
            if (!assetMatcher(name))
            {
                continue;
            }

            var url = asset.GetProperty("browser_download_url").GetString();
            if (!string.IsNullOrWhiteSpace(url))
            {
                return url;
            }
        }

        throw new InvalidOperationException($"No matching asset found for release: {apiUrl}");
    }

    private static async Task DownloadFileAsync(string url, string destination, CancellationToken cancellationToken)
    {
        Directory.CreateDirectory(Path.GetDirectoryName(destination)!);

        using var response = await Http.GetAsync(url, HttpCompletionOption.ResponseHeadersRead, cancellationToken)
            .ConfigureAwait(false);
        response.EnsureSuccessStatusCode();

        await using var input = await response.Content.ReadAsStreamAsync(cancellationToken).ConfigureAwait(false);
        await using var output = File.Create(destination);
        await input.CopyToAsync(output, cancellationToken).ConfigureAwait(false);
    }

    private static async Task ExtractExeFromZipAsync(
        string zipPath,
        string destinationExe,
        string exeName,
        CancellationToken cancellationToken)
    {
        await Task.Run(() =>
        {
            using var archive = ZipFile.OpenRead(zipPath);
            var entry = archive.Entries.FirstOrDefault(e =>
                e.Name.Equals(exeName, StringComparison.OrdinalIgnoreCase));

            if (entry is null)
            {
                entry = archive.Entries.FirstOrDefault(e =>
                    e.FullName.EndsWith(exeName, StringComparison.OrdinalIgnoreCase));
            }

            if (entry is null)
            {
                throw new InvalidOperationException($"{exeName} not found in archive {zipPath}.");
            }

            entry.ExtractToFile(destinationExe, overwrite: true);
        }, cancellationToken).ConfigureAwait(false);
    }
}

using System.Diagnostics;
using Microsoft.Extensions.Logging;
using NapsternetVClient.Network;
using NapsternetVClient.Utilities;

namespace NapsternetVClient.Core;

public sealed class ProcessGuard
{
    private readonly ILogger? _logger;
    private readonly SystemProxyManager _proxyManager;
    private readonly KillSwitchManager _killSwitchManager;

    public ProcessGuard(
        SystemProxyManager? proxyManager = null,
        KillSwitchManager? killSwitchManager = null,
        ILogger? logger = null)
    {
        _proxyManager = proxyManager ?? new SystemProxyManager(logger);
        _killSwitchManager = killSwitchManager ?? new KillSwitchManager(logger);
        _logger = logger;
    }

    public void RecoverFromDirtySession()
    {
        if (!File.Exists(Constants.LockFile))
        {
            return;
        }

        _logger?.LogWarning("Detected dirty session lock file. Performing cleanup...");

        KillProcessByName("xray");
        KillProcessByName("sing-box");

        try
        {
            _proxyManager.Restore();
        }
        catch (Exception ex)
        {
            _logger?.LogWarning(ex, "Failed to restore system proxy during dirty session cleanup.");
        }

        try
        {
            _killSwitchManager.Disable();
        }
        catch (Exception ex)
        {
            _logger?.LogWarning(ex, "Failed to disable kill switch during dirty session cleanup.");
        }

        TryDeleteLockFile();
        _logger?.LogInformation("Dirty session cleanup completed.");
    }

    public void MarkConnected()
    {
        Constants.EnsureDirectories();
        File.WriteAllText(Constants.LockFile, DateTimeOffset.UtcNow.ToString("O"));
    }

    public void MarkDisconnected()
    {
        TryDeleteLockFile();
    }

    public bool IsDirtySession() => File.Exists(Constants.LockFile);

    private static void KillProcessByName(string processName)
    {
        foreach (var process in Process.GetProcessesByName(processName))
        {
            try
            {
                if (!process.HasExited)
                {
                    process.Kill(entireProcessTree: true);
                }
            }
            catch
            {
                // Best effort.
            }
            finally
            {
                process.Dispose();
            }
        }
    }

    private void TryDeleteLockFile()
    {
        try
        {
            if (File.Exists(Constants.LockFile))
            {
                File.Delete(Constants.LockFile);
            }
        }
        catch (Exception ex)
        {
            _logger?.LogWarning(ex, "Failed to delete lock file.");
        }
    }
}

